function solve(prices, strategy, k) {
    let maxProfit = 0;
    const n = prices.length;

    // Calculate the original profit
    let originalProfit = 0;
    for (let i = 0; i < n; i++) {
        originalProfit += strategy[i] * prices[i];
    }
    maxProfit = originalProfit;

    // Try to improve the profit by modifying a subarray of length k
    for (let i = 0; i <= n - k; i++) {
        // Calculate the profit change if we modify the subarray starting at i
        let profitChange = 0;
        // For the first k/2 elements, change from -1 to 0 (buy to hold)
        for (let j = 0; j < k / 2; j++) {
            profitChange += (0 - strategy[i + j]) * prices[i + j];
        }
        // For the next k/2 elements, change from 0 to 1 (hold to sell)
        for (let j = k / 2; j < k; j++) {
            profitChange += (1 - strategy[i + j]) * prices[i + j];
        }
        // Update the maximum profit
        maxProfit = Math.max(maxProfit, originalProfit + profitChange);
    }

    return maxProfit;
}

